local jwt = require "resty.jwt"
local cjson = require "cjson"

local function has_permission(user_role, required_role)
    if user_role == required_role or user_role == "admin" then
        return true
    end
    return false
end

local function validate_token(token)
    if not token then
        return nil, "Missing token"
    end
    
    local jwt_obj = jwt:verify(os.getenv("JWT_SECRET") or "your-secret-key", token)
    
    if not jwt_obj.verified then
        return nil, "Invalid token"
    end
    
    return jwt_obj.payload, nil
end

local function is_public_endpoint(uri)
    local public_endpoints = {
        "^/health$",
        "^/login$",
        "^/register$",
        "^/public/",
    }
    
    for _, pattern in ipairs(public_endpoints) do
        if ngx.re.match(uri, pattern, "jo") then
            return true
        end
    end
    
    return false
end

local function requires_admin(uri)
    if ngx.re.match(uri, "^/admin/", "jo") then
        return true
    end
    return false
end

local function requires_api_access(uri)
    if ngx.re.match(uri, "^/api/", "jo") then
        return true
    end
    return false
end

local uri = ngx.var.uri

if is_public_endpoint(uri) then
    return
end

local auth_header = ngx.var.http_authorization
if not auth_header then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header.content_type = "application/json"
    ngx.say(cjson.encode({error = "Authorization header required"}))
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local token = string.match(auth_header, "^Bearer%s+(.+)$")
if not token then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header.content_type = "application/json"
    ngx.say(cjson.encode({error = "Invalid authorization format"}))
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

